    39→  void initialize(const std::string& yaml_config, bool uses_tls) {
    40→    envoy::config::cluster::v3::Cluster cluster_config =
    41→        Upstream::parseClusterFromV3Yaml(yaml_config);
    42→    envoy::extensions::clusters::dynamic_forward_proxy::v3::ClusterConfig config;
    43→    Config::Utility::translateOpaqueConfig(cluster_config.cluster_type().typed_config(),
    44→                                           ProtobufMessage::getStrictValidationVisitor(), config);
    45→
    46→    Envoy::Upstream::ClusterFactoryContextImpl factory_context(
    47→        server_context_, server_context_.cluster_manager_, nullptr, ssl_context_manager_, nullptr,
    48→        false);
    49→
    50→    ON_CALL(server_context_, api()).WillByDefault(testing::ReturnRef(*api_));
    51→
    52→    if (uses_tls) {
    53→      EXPECT_CALL(ssl_context_manager_, createSslClientContext(_, _));
    54→    }
    55→    EXPECT_CALL(*dns_cache_manager_, getCache(_));
    56→    // Below we return a nullptr handle which has no effect on the code under test but isn't
    57→    // actually correct. It's possible this will have to change in the future.
    58→    EXPECT_CALL(*dns_cache_manager_->dns_cache_, addUpdateCallbacks_(_))
    59→        .WillOnce(DoAll(SaveArgAddress(&update_callbacks_), Return(nullptr)));
    60→    auto cache = dns_cache_manager_->getCache(config.dns_cache_config()).value();
    61→    cluster_.reset(
    62→        new Cluster(cluster_config, std::move(cache), config, factory_context, this->get()));
    63→    thread_aware_lb_ = std::make_unique<Cluster::ThreadAwareLoadBalancer>(*cluster_);
    64→    lb_factory_ = thread_aware_lb_->factory();
    65→    refreshLb();
    66→
    67→    ON_CALL(lb_context_, downstreamHeaders()).WillByDefault(Return(&downstream_headers_));
    68→    ON_CALL(connection_, streamInfo()).WillByDefault(ReturnRef(stream_info_));
    69→    ON_CALL(lb_context_, requestStreamInfo()).WillByDefault(Return(&stream_info_));
    70→    ON_CALL(lb_context_, downstreamConnection()).WillByDefault(Return(&connection_));
    71→
    72→    member_update_cb_ = cluster_->prioritySet().addMemberUpdateCb(
    73→        [this](const Upstream::HostVector& hosts_added,
    74→               const Upstream::HostVector& hosts_removed) -> void {
    75→          onMemberUpdateCb(hosts_added, hosts_removed);
    76→        });
    77→
    78→    absl::flat_hash_map<std::string, Extensions::Common::DynamicForwardProxy::DnsHostInfoSharedPtr>
    79→        existing_hosts;
    80→    for (const auto& host : host_map_) {
    81→      existing_hosts.emplace(host.first, host.second);
    82→    }
    83→    EXPECT_CALL(*dns_cache_manager_->dns_cache_, iterateHostMap(_)).WillOnce(Invoke([&](auto cb) {
    84→      for (const auto& host : host_map_) {
    85→        cb(host.first, host.second);
    86→      }
    87→    }));
    88→    if (!existing_hosts.empty()) {
    89→      EXPECT_CALL(*this, onMemberUpdateCb(SizeIs(existing_hosts.size()), SizeIs(0)));
    90→    }
    91→    cluster_->initialize([] {});
    92→  }
