   236→// Basic flow of the cluster including adding hosts and removing them.
   237→TEST_F(ClusterTest, BasicFlow) {
   238→  initialize(default_yaml_config_, false);
   239→  makeTestHost("host1:0", "1.2.3.4");
   240→  InSequence s;
   241→
   242→  EXPECT_EQ(nullptr, lb_->chooseHost(setHostAndReturnContext("")));
   243→
   244→  // Verify no host LB cases.
   245→  EXPECT_EQ(nullptr, lb_->chooseHost(setHostAndReturnContext("foo")));
   246→  EXPECT_EQ(nullptr, lb_->peekAnotherHost(setHostAndReturnContext("foo")));
   247→
   248→  // LB will immediately resolve host1.
   249→  EXPECT_CALL(*this, onMemberUpdateCb(SizeIs(1), SizeIs(0)));
   250→  update_callbacks_->onDnsHostAddOrUpdate("host1:0", host_map_["host1:0"]);
   251→  EXPECT_EQ(1UL, cluster_->prioritySet().hostSetsPerPriority()[0]->hosts().size());
   252→  EXPECT_EQ("1.2.3.4:0",
   253→            cluster_->prioritySet().hostSetsPerPriority()[0]->hosts()[0]->address()->asString());
   254→  EXPECT_CALL(*host_map_["host1:0"], touch());
   255→  EXPECT_EQ("1.2.3.4:0",
   256→            lb_->chooseHost(setHostAndReturnContext("host1:0"))->address()->asString());
   257→
   258→  // After changing the address, LB will immediately resolve the new address with a refresh.
   259→  updateTestHostAddress("host1:0", "2.3.4.5");
   260→  update_callbacks_->onDnsHostAddOrUpdate("host1:0", host_map_["host1:0"]);
   261→  EXPECT_EQ(1UL, cluster_->prioritySet().hostSetsPerPriority()[0]->hosts().size());
   262→  EXPECT_EQ("2.3.4.5:0",
   263→            cluster_->prioritySet().hostSetsPerPriority()[0]->hosts()[0]->address()->asString());
   264→  EXPECT_CALL(*host_map_["host1:0"], touch());
   265→  EXPECT_EQ("2.3.4.5:0",
   266→            lb_->chooseHost(setHostAndReturnContext("host1:0"))->address()->asString());
   267→
   268→  // Remove the host, LB will immediately fail to find the host in the map.
   269→  EXPECT_CALL(*this, onMemberUpdateCb(SizeIs(0), SizeIs(1)));
   270→  update_callbacks_->onDnsHostRemove("host1:0");
   271→  EXPECT_EQ(0UL, cluster_->prioritySet().hostSetsPerPriority()[0]->hosts().size());
   272→  EXPECT_EQ(nullptr, lb_->chooseHost(setHostAndReturnContext("host1:0")));
   273→}
