   435→TEST_F(ClusterTest, LoadBalancer_SelectPoolNoMatchingConnectionAfterDraining) {
   436→  initialize(coalesce_connection_config_, false);
   437→
   438→  const std::string hostname = "mail.example.org";
   439→  Upstream::MockHost host;
   440→  EXPECT_CALL(host, hostname()).WillRepeatedly(testing::ReturnRef(hostname));
   441→  Network::Address::InstanceConstSharedPtr address =
   442→      Network::Utility::resolveUrl("tcp://10.0.0.3:50000");
   443→  EXPECT_CALL(host, address()).WillRepeatedly(testing::Return(address));
   444→  std::vector<uint8_t> hash_key = {1, 2, 3};
   445→
   446→  Envoy::Http::ConnectionPool::MockInstance pool;
   447→  Envoy::Network::MockConnection connection;
   448→  OptRef<Envoy::Http::ConnectionPool::ConnectionLifetimeCallbacks> lifetime_callbacks =
   449→      lb_->lifetimeCallbacks();
   450→  ASSERT_TRUE(lifetime_callbacks.has_value());
   451→
   452→  EXPECT_CALL(connection, connectionInfoProvider()).Times(testing::AnyNumber());
   453→  EXPECT_CALL(connection, nextProtocol()).WillRepeatedly(Return("h2"));
   454→  auto ssl_info = std::make_shared<Ssl::MockConnectionInfo>();
   455→  EXPECT_CALL(connection, ssl()).WillRepeatedly(Return(ssl_info));
   456→  lifetime_callbacks->onConnectionOpen(pool, hash_key, connection);
   457→
