   276→TEST_F(ClusterTest, OutlierDetection) {
   277→  initialize(default_yaml_config_, false);
   278→  makeTestHost("host1:0", "1.2.3.4");
   279→  makeTestHost("host2:0", "5.6.7.8");
   280→  InSequence s;
   281→
   282→  EXPECT_CALL(*this, onMemberUpdateCb(SizeIs(1), SizeIs(0)));
   283→  update_callbacks_->onDnsHostAddOrUpdate("host1:0", host_map_["host1:0"]);
   284→  EXPECT_CALL(*host_map_["host1:0"], touch());
   285→  EXPECT_EQ("1.2.3.4:0",
   286→            lb_->chooseHost(setHostAndReturnContext("host1:0"))->address()->asString());
   287→
   288→  EXPECT_CALL(*this, onMemberUpdateCb(SizeIs(1), SizeIs(0)));
   289→  update_callbacks_->onDnsHostAddOrUpdate("host2:0", host_map_["host2:0"]);
   290→  EXPECT_CALL(*host_map_["host2:0"], touch());
   291→  EXPECT_EQ("5.6.7.8:0",
   292→            lb_->chooseHost(setHostAndReturnContext("host2:0"))->address()->asString());
   293→
   294→  // Fail outlier check for host1
   295→  setOutlierFailed("host1:0");
   296→  EXPECT_EQ(nullptr, lb_->chooseHost(setHostAndReturnContext("host1:0")));
