   475→absl::StatusOr<std::pair<Upstream::ClusterImplBaseSharedPtr, Upstream::ThreadAwareLoadBalancerPtr>>
   476→ClusterFactory::createClusterWithConfig(
   477→    const envoy::config::cluster::v3::Cluster& cluster,
   478→    const envoy::extensions::clusters::dynamic_forward_proxy::v3::ClusterConfig& proto_config,
   479→    Upstream::ClusterFactoryContext& context) {
   480→
   481→  Extensions::Common::DynamicForwardProxy::DnsCacheManagerFactoryImpl cache_manager_factory(
   482→      context.serverFactoryContext(), context.messageValidationVisitor());
   483→
   484→  envoy::config::cluster::v3::Cluster cluster_config = cluster;
   485→  if (!cluster_config.has_upstream_http_protocol_options()) {
   486→    // This sets defaults which will only apply if using old style http config.
   487→    // They will be a no-op if typed_extension_protocol_options are used for
   488→    // http config.
   489→    cluster_config.mutable_upstream_http_protocol_options()->set_auto_sni(true);
   490→    cluster_config.mutable_upstream_http_protocol_options()->set_auto_san_validation(true);
   491→  }
   492→
   493→  Extensions::Common::DynamicForwardProxy::DnsCacheManagerSharedPtr cache_manager =
   494→      cache_manager_factory.get();
   495→  auto dns_cache_or_error = cache_manager->getCache(proto_config.dns_cache_config());
   496→  RETURN_IF_STATUS_NOT_OK(dns_cache_or_error);
   497→
   498→  auto new_cluster =
   499→      std::shared_ptr<Cluster>(new Cluster(cluster_config, std::move(dns_cache_or_error.value()),
   500→                                           proto_config, context, std::move(cache_manager)));
   501→
   502→  Extensions::Common::DynamicForwardProxy::DFPClusterStoreFactory cluster_store_factory(
   503→      context.serverFactoryContext().singletonManager());
   504→  cluster_store_factory.get()->save(new_cluster->info()->name(), new_cluster);
   505→
   506→  auto& options = new_cluster->info()->upstreamHttpProtocolOptions();
   507→
   508→  if (!proto_config.allow_insecure_cluster_options()) {
   509→    if (!options.has_value() ||
   510→        (!options.value().auto_sni() || !options.value().auto_san_validation())) {
   511→      return absl::InvalidArgumentError(
   512→          "dynamic_forward_proxy cluster must have auto_sni and auto_san_validation true unless "
   513→          "allow_insecure_cluster_options is set.");
   514→    }
   515→  }
   516→  if (proto_config.has_sub_clusters_config() &&
   517→      proto_config.sub_clusters_config().lb_policy() ==
   518→          envoy::config::cluster::v3::Cluster_LbPolicy::Cluster_LbPolicy_CLUSTER_PROVIDED) {
   519→    return absl::InvalidArgumentError(
   520→        "unsupported lb_policy 'CLUSTER_PROVIDED' in sub_cluster_config");
   521→  }
   522→
   523→  auto lb = std::make_unique<Cluster::ThreadAwareLoadBalancer>(*new_cluster);
   524→  return std::make_pair(new_cluster, std::move(lb));
   525→}
