   149→      cluster_it->second->touch();
   150→      return std::make_pair(true, absl::nullopt);
   151→    }
   152→    if (cluster_map_.size() >= max_sub_clusters_) {
   153→      ENVOY_LOG(debug, "cluster='{}' create failed due to max sub cluster limitation",
   154→                cluster_name);
   155→      return std::make_pair(false, absl::nullopt);
   156→    }
   157→    cluster_map_.emplace(cluster_name, std::make_shared<ClusterInfo>(cluster_name, *this));
   158→  }
   159→
   160→  // Inherit configuration from the parent DFP cluster.
   161→  envoy::config::cluster::v3::Cluster config = orig_cluster_config_;
   162→
   163→  // Overwrite the type.
   164→  config.set_name(cluster_name);
   165→  config.clear_cluster_type();
   166→  config.set_lb_policy(sub_cluster_lb_policy_);
   167→  config.set_type(
   168→      envoy::config::cluster::v3::Cluster_DiscoveryType::Cluster_DiscoveryType_STRICT_DNS);
   169→
   170→  // Set endpoint.
   171→  auto load_assignments = config.mutable_load_assignment();
   172→  load_assignments->set_cluster_name(cluster_name);
   173→  load_assignments->clear_endpoints();
   174→
   175→  auto socket_address = load_assignments->add_endpoints()
   176→                            ->add_lb_endpoints()
   177→                            ->mutable_endpoint()
   178→                            ->mutable_address()
   179→                            ->mutable_socket_address();
   180→  socket_address->set_address(host);
   181→  socket_address->set_port_value(port);
   182→
   183→  return std::make_pair(true, absl::make_optional(config));
   184→}
   185→
   186→Upstream::HostConstSharedPtr Cluster::chooseHost(absl::string_view host,
   187→                                                 Upstream::LoadBalancerContext* context) const {
   188→  uint16_t default_port = 80;
   189→  if (info_->transportSocketMatcher().resolve(nullptr).factory_.implementsSecureTransport()) {
   190→    default_port = 443;
   191→  }
   192→
   193→  const auto host_attributes = Http::Utility::parseAuthority(host);
   194→  auto dynamic_host = std::string(host_attributes.host_);
   195→  auto port = host_attributes.port_.value_or(default_port);
   196→
   197→  // cluster name is prefix + host + port
   198→  auto cluster_name = "DFPCluster:" + dynamic_host + ":" + std::to_string(port);
   199→
   200→  // try again to get the sub cluster.
   201→  auto cluster = cm_.getThreadLocalCluster(cluster_name);
   202→  if (cluster == nullptr) {
   203→    ENVOY_LOG(debug, "cluster='{}' get thread local failed, too short ttl?", cluster_name);
   204→    return nullptr;
   205→  }
   206→
   207→  return cluster->loadBalancer().chooseHost(context);
   208→}
