   210→Cluster::ClusterInfo::ClusterInfo(std::string cluster_name, Cluster& parent)
   211→    : cluster_name_(cluster_name), parent_(parent) {
   212→  ENVOY_LOG(debug, "cluster='{}' ClusterInfo created", cluster_name_);
   213→  touch();
