   216→void Cluster::ClusterInfo::touch() {
   217→  ENVOY_LOG(debug, "cluster='{}' updating last used time", cluster_name_);
   218→  last_used_time_ = parent_.time_source_.monotonicTime().time_since_epoch();
   219→}
   220→
   221→// checkIdle run in the main thread.
   222→bool Cluster::ClusterInfo::checkIdle() {
   223→  ASSERT(parent_.main_thread_dispatcher_.isThreadSafe());
   224→
   225→  const std::chrono::steady_clock::duration now_duration =
   226→      parent_.main_thread_dispatcher_.timeSource().monotonicTime().time_since_epoch();
   227→  auto last_used_time = last_used_time_.load();
   228→  ENVOY_LOG(debug, "cluster='{}' TTL check: now={} last_used={} TTL {}", cluster_name_,
   229→            now_duration.count(), last_used_time.count(), parent_.sub_cluster_ttl_.count());
   230→
   231→  if ((now_duration - last_used_time) > parent_.sub_cluster_ttl_) {
   232→    ENVOY_LOG(debug, "cluster='{}' TTL expired", cluster_name_);
   233→    return true;
   234→  }
   235→  return false;
   236→}
   237→
   238→void Cluster::addOrUpdateHost(
   239→    absl::string_view host,
   240→    const Extensions::Common::DynamicForwardProxy::DnsHostInfoSharedPtr& host_info,
   241→    std::unique_ptr<Upstream::HostVector>& hosts_added) {
   242→  Upstream::LogicalHostSharedPtr emplaced_host;
   243→  {
   244→    absl::WriterMutexLock lock{&host_map_lock_};
   245→
   246→    // NOTE: Right now we allow a DNS cache to be shared between multiple clusters. Though we have
   247→    // connection/request circuit breakers on the cluster, we don't have any way to control the
   248→    // maximum hosts on a cluster. We currently assume that host data shared via shared pointer is
   249→    // a marginal memory cost above that already used by connections and requests, so relying on
   250→    // connection/request circuit breakers is sufficient. We may have to revisit this in the
   251→    // future.
   252→    const auto host_map_it = host_map_.find(host);
   253→    if (host_map_it != host_map_.end()) {
   254→      // If we only have an address change, we can do that swap inline without any other updates.
   255→      // The appropriate R/W locking is in place to allow this. The details of this locking are:
   256→      //  - Hosts are not thread local, they are global.
   257→      //  - We take a read lock when reading the address and a write lock when changing it.
   258→      //  - Address updates are very rare.
   259→      //  - Address reads are only done when a connection is being made and a "real" host
   260→      //    description is created or the host is queried via the admin endpoint. Both of
   261→      //    these operations are relatively rare and the read lock is held for a short period
   262→      //    of time.
   263→      //
   264→      // TODO(mattklein123): Right now the dynamic forward proxy / DNS cache works similar to how
   265→      //                     logical DNS works, meaning that we only store a single address per
   266→      //                     resolution. It would not be difficult to also expose strict DNS
   267→      //                     semantics, meaning the cache would expose multiple addresses and the
   268→      //                     cluster would create multiple logical hosts based on those addresses.
   269→      //                     We will leave this is a follow up depending on need.
   270→      ASSERT(host_info == host_map_it->second.shared_host_info_);
   271→      ASSERT(host_map_it->second.shared_host_info_->address() !=
   272→             host_map_it->second.logical_host_->address());
   273→      ENVOY_LOG(debug, "updating dfproxy cluster host address '{}'", host);
   274→      host_map_it->second.logical_host_->setNewAddresses(
   275→          host_info->address(), host_info->addressList(), dummy_lb_endpoint_);
   276→      return;
   277→    }
   278→
   279→    ENVOY_LOG(debug, "adding new dfproxy cluster host '{}'", host);
   280→
   281→    emplaced_host = host_map_
   282→                        .try_emplace(host, host_info,
   283→                                     std::make_shared<Upstream::LogicalHost>(
   284→                                         info(), std::string{host}, host_info->address(),
   285→                                         host_info->addressList(), dummy_locality_lb_endpoint_,
   286→                                         dummy_lb_endpoint_, nullptr, time_source_))
   287→                        .first->second.logical_host_;
   288→  }
   289→
   290→  ASSERT(emplaced_host);
   291→  if (hosts_added == nullptr) {
   292→    hosts_added = std::make_unique<Upstream::HostVector>();
   293→  }
   294→  hosts_added->emplace_back(emplaced_host);
   295→}
   296→
   297→void Cluster::onDnsHostAddOrUpdate(
   298→    const std::string& host,
   299→    const Extensions::Common::DynamicForwardProxy::DnsHostInfoSharedPtr& host_info) {
   300→  ENVOY_LOG(debug, "Adding host info for {}", host);
   301→
   302→  std::unique_ptr<Upstream::HostVector> hosts_added;
   303→  addOrUpdateHost(host, host_info, hosts_added);
   304→  if (hosts_added != nullptr) {
   305→    ASSERT(!hosts_added->empty());
   306→    updatePriorityState(*hosts_added, {});
   307→  }
   308→}
   309→
   310→void Cluster::updatePriorityState(const Upstream::HostVector& hosts_added,
   311→                                  const Upstream::HostVector& hosts_removed) {
   312→  Upstream::PriorityStateManager priority_state_manager(*this, local_info_, nullptr);
   313→  priority_state_manager.initializePriorityFor(dummy_locality_lb_endpoint_);
   314→  {
   315→    absl::ReaderMutexLock lock{&host_map_lock_};
   316→    for (const auto& host : host_map_) {
   317→      priority_state_manager.registerHostForPriority(host.second.logical_host_,
   318→                                                     dummy_locality_lb_endpoint_);
   319→    }
   320→  }
   321→  priority_state_manager.updateClusterPrioritySet(
   322→      0, std::move(priority_state_manager.priorityState()[0].first), hosts_added, hosts_removed,
   323→      absl::nullopt, absl::nullopt, absl::nullopt);
   324→}
   325→
   326→void Cluster::onDnsHostRemove(const std::string& host) {
   327→  Upstream::HostVector hosts_removed;
   328→  {
   329→    absl::WriterMutexLock lock{&host_map_lock_};
   330→    const auto host_map_it = host_map_.find(host);
   331→    ASSERT(host_map_it != host_map_.end());
   332→    hosts_removed.emplace_back(host_map_it->second.logical_host_);
   333→    host_map_.erase(host);
   334→    ENVOY_LOG(debug, "removing dfproxy cluster host '{}'", host);
   335→  }
   336→  updatePriorityState({}, hosts_removed);
   337→}
   338→
   339→Upstream::HostConstSharedPtr
   340→Cluster::LoadBalancer::chooseHost(Upstream::LoadBalancerContext* context) {
   341→  if (!context) {
   342→    return nullptr;
   343→  }
   344→
   345→  const Router::StringAccessor* dynamic_host_filter_state = nullptr;
   346→  if (context->requestStreamInfo()) {
   347→    dynamic_host_filter_state =
   348→        context->requestStreamInfo()->filterState().getDataReadOnly<Router::StringAccessor>(
   349→            DynamicHostFilterStateKey);
   350→  }
   351→
   352→  absl::string_view raw_host;
   353→  if (dynamic_host_filter_state) {
   354→    raw_host = dynamic_host_filter_state->asString();
   355→  } else if (context->downstreamHeaders()) {
   356→    raw_host = context->downstreamHeaders()->getHostValue();
   357→  } else if (context->downstreamConnection()) {
   358→    raw_host = context->downstreamConnection()->requestedServerName();
   359→  }
   360→
   361→  // For host lookup, we need to make sure to match the host of any DNS cache
   362→  // insert. Two code points currently do DNS cache insert: the http DFP filter,
   363→  // which inserts for HTTP traffic, and sets port based on the cluster's
   364→  // security level, and the SNI DFP network filter which sets port based on
   365→  // stream metadata, or configuration (which is then added as stream metadata).
   366→  const bool is_secure = cluster_.info()
   367→                             ->transportSocketMatcher()
   368→                             .resolve(nullptr)
   369→                             .factory_.implementsSecureTransport();
   370→  uint32_t port = is_secure ? 443 : 80;
   371→  if (context->requestStreamInfo()) {
   372→    const StreamInfo::UInt32Accessor* dynamic_port_filter_state =
   373→        context->requestStreamInfo()->filterState().getDataReadOnly<StreamInfo::UInt32Accessor>(
   374→            DynamicPortFilterStateKey);
   375→    if (dynamic_port_filter_state != nullptr && dynamic_port_filter_state->value() > 0 &&
   376→        dynamic_port_filter_state->value() <= 65535) {
   377→      port = dynamic_port_filter_state->value();
   378→    }
   379→  }
   380→
   381→  std::string host = Common::DynamicForwardProxy::DnsHostInfo::normalizeHostForDfp(raw_host, port);
   382→
   383→  if (host.empty()) {
   384→    ENVOY_LOG(debug, "host empty");
   385→    return nullptr;
   386→  }
   387→
   388→  if (cluster_.enableSubCluster()) {
   389→    return cluster_.chooseHost(host, context);
   390→  }
   391→
   392→  {
   393→    absl::ReaderMutexLock lock{&cluster_.host_map_lock_};
   394→    const auto host_it = cluster_.host_map_.find(host);
   395→    if (host_it == cluster_.host_map_.end()) {
   396→      ENVOY_LOG(debug, "host {} not found", host);
   397→      return nullptr;
   398→    } else {
   399→      if (host_it->second.logical_host_->coarseHealth() == Upstream::Host::Health::Unhealthy) {
   400→        ENVOY_LOG(debug, "host {} is unhealthy", host);
   401→        return nullptr;
   402→      }
   403→      host_it->second.shared_host_info_->touch();
   404→      return host_it->second.logical_host_;
   405→    }
   406→  }
   407→}
   408→
   409→absl::optional<Upstream::SelectedPoolAndConnection>
   410→Cluster::LoadBalancer::selectExistingConnection(Upstream::LoadBalancerContext* /*context*/,
   411→                                                const Upstream::Host& host,
   412→                                                std::vector<uint8_t>& hash_key) {
   413→  const std::string& hostname = host.hostname();
   414→  if (hostname.empty()) {
   415→    return absl::nullopt;
   416→  }
   417→
   418→  LookupKey key = {hash_key, *host.address()};
   419→  auto it = connection_info_map_.find(key);
   420→  if (it == connection_info_map_.end()) {
   421→    return absl::nullopt;
   422→  }
   423→
   424→  for (auto& info : it->second) {
   425→    Envoy::Ssl::ConnectionInfoConstSharedPtr ssl = info.connection_->ssl();
   426→    ASSERT(ssl);
   427→    for (const std::string& san : ssl->dnsSansPeerCertificate()) {
   428→      if (Extensions::TransportSockets::Tls::Utility::dnsNameMatch(hostname, san)) {
   429→        return Upstream::SelectedPoolAndConnection{*info.pool_, *info.connection_};
   430→      }
   431→    }
   432→  }
   433→
   434→  return absl::nullopt;
   435→}
   436→
   437→OptRef<Envoy::Http::ConnectionPool::ConnectionLifetimeCallbacks>
   438→Cluster::LoadBalancer::lifetimeCallbacks() {
   439→  if (!cluster_.allowCoalescedConnections()) {
   440→    return {};
   441→  }
   442→  return makeOptRef<Envoy::Http::ConnectionPool::ConnectionLifetimeCallbacks>(*this);
   443→}
   444→
   445→void Cluster::LoadBalancer::onConnectionOpen(Envoy::Http::ConnectionPool::Instance& pool,
   446→                                             std::vector<uint8_t>& hash_key,
   447→                                             const Network::Connection& connection) {
   448→  // Only coalesce connections that are over TLS.
   449→  if (!connection.ssl()) {
   450→    return;
   451→  }
   452→  const std::string alpn = connection.nextProtocol();
   453→  if (alpn != Http::Utility::AlpnNames::get().Http2 &&
   454→      alpn != Http::Utility::AlpnNames::get().Http3) {
   455→    // Only coalesce connections for HTTP/2 and HTTP/3.
   456→    return;
   457→  }
   458→  const LookupKey key = {hash_key, *connection.connectionInfoProvider().remoteAddress()};
   459→  ConnectionInfo info = {&pool, &connection};
   460→  connection_info_map_[key].push_back(info);
   461→}
   462→
   463→void Cluster::LoadBalancer::onConnectionDraining(Envoy::Http::ConnectionPool::Instance& pool,
   464→                                                 std::vector<uint8_t>& hash_key,
   465→                                                 const Network::Connection& connection) {
   466→  const LookupKey key = {hash_key, *connection.connectionInfoProvider().remoteAddress()};
   467→  connection_info_map_[key].erase(
   468→      std::remove_if(connection_info_map_[key].begin(), connection_info_map_[key].end(),
   469→                     [&pool, &connection](const ConnectionInfo& info) {
   470→                       return (info.pool_ == &pool && info.connection_ == &connection);
   471→                     }),
   472→      connection_info_map_[key].end());
   473→}
   474→
   475→absl::StatusOr<std::pair<Upstream::ClusterImplBaseSharedPtr, Upstream::ThreadAwareLoadBalancerPtr>>
   476→ClusterFactory::createClusterWithConfig(
   477→    const envoy::config::cluster::v3::Cluster& cluster,
   478→    const envoy::extensions::clusters::dynamic_forward_proxy::v3::ClusterConfig& proto_config,
   479→    Upstream::ClusterFactoryContext& context) {
   480→
   481→  Extensions::Common::DynamicForwardProxy::DnsCacheManagerFactoryImpl cache_manager_factory(
   482→      context.serverFactoryContext(), context.messageValidationVisitor());
   483→
   484→  envoy::config::cluster::v3::Cluster cluster_config = cluster;
   485→  if (!cluster_config.has_upstream_http_protocol_options()) {
   486→    // This sets defaults which will only apply if using old style http config.
   487→    // They will be a no-op if typed_extension_protocol_options are used for
   488→    // http config.
   489→    cluster_config.mutable_upstream_http_protocol_options()->set_auto_sni(true);
   490→    cluster_config.mutable_upstream_http_protocol_options()->set_auto_san_validation(true);
   491→  }
   492→
   493→  Extensions::Common::DynamicForwardProxy::DnsCacheManagerSharedPtr cache_manager =
   494→      cache_manager_factory.get();
   495→  auto dns_cache_or_error = cache_manager->getCache(proto_config.dns_cache_config());
   496→  RETURN_IF_STATUS_NOT_OK(dns_cache_or_error);
   497→
   498→  auto new_cluster =
   499→      std::shared_ptr<Cluster>(new Cluster(cluster_config, std::move(dns_cache_or_error.value()),
   500→                                           proto_config, context, std::move(cache_manager)));
   501→
   502→  Extensions::Common::DynamicForwardProxy::DFPClusterStoreFactory cluster_store_factory(
   503→      context.serverFactoryContext().singletonManager());
   504→  cluster_store_factory.get()->save(new_cluster->info()->name(), new_cluster);
   505→
   506→  auto& options = new_cluster->info()->upstreamHttpProtocolOptions();
   507→
   508→  if (!proto_config.allow_insecure_cluster_options()) {
   509→    if (!options.has_value() ||
   510→        (!options.value().auto_sni() || !options.value().auto_san_validation())) {
   511→      return absl::InvalidArgumentError(
   512→          "dynamic_forward_proxy cluster must have auto_sni and auto_san_validation true unless "
   513→          "allow_insecure_cluster_options is set.");
   514→    }
   515→  }
   516→  if (proto_config.has_sub_clusters_config() &&
   517→      proto_config.sub_clusters_config().lb_policy() ==
   518→          envoy::config::cluster::v3::Cluster_LbPolicy::Cluster_LbPolicy_CLUSTER_PROVIDED) {
   519→    return absl::InvalidArgumentError(
   520→        "unsupported lb_policy 'CLUSTER_PROVIDED' in sub_cluster_config");
   521→  }
   522→
   523→  auto lb = std::make_unique<Cluster::ThreadAwareLoadBalancer>(*new_cluster);
   524→  return std::make_pair(new_cluster, std::move(lb));
   525→}
   526→
   527→REGISTER_FACTORY(ClusterFactory, Upstream::ClusterFactory);
   528→
   529→} // namespace DynamicForwardProxy
   530→} // namespace Clusters
   531→} // namespace Extensions
   532→} // namespace Envoy
