   180→  socket_address->set_address(host);
   181→  socket_address->set_port_value(port);
   182→
   183→  return std::make_pair(true, absl::make_optional(config));
   184→}
   185→
   186→Upstream::HostConstSharedPtr Cluster::chooseHost(absl::string_view host,
   187→                                                 Upstream::LoadBalancerContext* context) const {
   188→  uint16_t default_port = 80;
   189→  if (info_->transportSocketMatcher().resolve(nullptr).factory_.implementsSecureTransport()) {
   190→    default_port = 443;
   191→  }
   192→
   193→  const auto host_attributes = Http::Utility::parseAuthority(host);
   194→  auto dynamic_host = std::string(host_attributes.host_);
   195→  auto port = host_attributes.port_.value_or(default_port);
   196→
   197→  // cluster name is prefix + host + port
   198→  auto cluster_name = "DFPCluster:" + dynamic_host + ":" + std::to_string(port);
   199→
   200→  // try again to get the sub cluster.
   201→  auto cluster = cm_.getThreadLocalCluster(cluster_name);
   202→  if (cluster == nullptr) {
   203→    ENVOY_LOG(debug, "cluster='{}' get thread local failed, too short ttl?", cluster_name);
   204→    return nullptr;
   205→  }
   206→
   207→  return cluster->loadBalancer().chooseHost(context);
   208→}
