   339→Upstream::HostConstSharedPtr
   340→Cluster::LoadBalancer::chooseHost(Upstream::LoadBalancerContext* context) {
   341→  if (!context) {
   342→    return nullptr;
   343→  }
   344→
   345→  const Router::StringAccessor* dynamic_host_filter_state = nullptr;
   346→  if (context->requestStreamInfo()) {
   347→    dynamic_host_filter_state =
   348→        context->requestStreamInfo()->filterState().getDataReadOnly<Router::StringAccessor>(
   349→            DynamicHostFilterStateKey);
   350→  }
   351→
   352→  absl::string_view raw_host;
   353→  if (dynamic_host_filter_state) {
   354→    raw_host = dynamic_host_filter_state->asString();
   355→  } else if (context->downstreamHeaders()) {
   356→    raw_host = context->downstreamHeaders()->getHostValue();
   357→  } else if (context->downstreamConnection()) {
   358→    raw_host = context->downstreamConnection()->requestedServerName();
   359→  }
   360→
   361→  // For host lookup, we need to make sure to match the host of any DNS cache
   362→  // insert. Two code points currently do DNS cache insert: the http DFP filter,
   363→  // which inserts for HTTP traffic, and sets port based on the cluster's
   364→  // security level, and the SNI DFP network filter which sets port based on
   365→  // stream metadata, or configuration (which is then added as stream metadata).
   366→  const bool is_secure = cluster_.info()
   367→                             ->transportSocketMatcher()
   368→                             .resolve(nullptr)
   369→                             .factory_.implementsSecureTransport();
   370→  uint32_t port = is_secure ? 443 : 80;
   371→  if (context->requestStreamInfo()) {
   372→    const StreamInfo::UInt32Accessor* dynamic_port_filter_state =
   373→        context->requestStreamInfo()->filterState().getDataReadOnly<StreamInfo::UInt32Accessor>(
   374→            DynamicPortFilterStateKey);
   375→    if (dynamic_port_filter_state != nullptr && dynamic_port_filter_state->value() > 0 &&
   376→        dynamic_port_filter_state->value() <= 65535) {
   377→      port = dynamic_port_filter_state->value();
   378→    }
   379→  }
   380→
   381→  std::string host = Common::DynamicForwardProxy::DnsHostInfo::normalizeHostForDfp(raw_host, port);
   382→
   383→  if (host.empty()) {
   384→    ENVOY_LOG(debug, "host empty");
   385→    return nullptr;
   386→  }
   387→
   388→  if (cluster_.enableSubCluster()) {
   389→    return cluster_.chooseHost(host, context);
   390→  }
   391→
   392→  {
   393→    absl::ReaderMutexLock lock{&cluster_.host_map_lock_};
   394→    const auto host_it = cluster_.host_map_.find(host);
   395→    if (host_it == cluster_.host_map_.end()) {
   396→      ENVOY_LOG(debug, "host {} not found", host);
   397→      return nullptr;
   398→    } else {
   399→      if (host_it->second.logical_host_->coarseHealth() == Upstream::Host::Health::Unhealthy) {
   400→        ENVOY_LOG(debug, "host {} is unhealthy", host);
   401→        return nullptr;
   402→      }
   403→      host_it->second.shared_host_info_->touch();
   404→      return host_it->second.logical_host_;
   405→    }
   406→  }
   407→}
